#Requires -RunAsAdministrator
$LP="$env:TEMP\driver-install-$(Get-Date -Format 'yyyyMMdd-HHmmss').log";$DP="$env:TEMP\driver-downloads";$ProgressPreference="SilentlyContinue";function WL([string]$M,[string]$L="INFO"){$ts=Get-Date -Format "yyyy-MM-dd HH:mm:ss";$log="[$ts] [$L] $M";Write-Host $log;Add-Content -Path $LP -Value $log -ErrorAction SilentlyContinue};function GetGPU{WL "Detecting GPU...";$gpu=@();try{$nv=Get-WmiObject Win32_VideoController|Where-Object{$_.Name -like "*NVIDIA*"};$nv|ForEach-Object{$gpu+=@{Type="NVIDIA";Name=$_.Name;DeviceID=$_.PNPDeviceID;Model=$_.Name};WL "Found NVIDIA GPU: $($_.Name)"}};catch{WL "NVIDIA detection error: $_" "WARN"};try{$amd=Get-WmiObject Win32_VideoController|Where-Object{$_.Name -like "*AMD*" -or $_.Name -like "*Radeon*"};$amd|ForEach-Object{$gpu+=@{Type="AMD";Name=$_.Name;DeviceID=$_.PNPDeviceID;Model=$_.Name};WL "Found AMD GPU: $($_.Name)"}};catch{WL "AMD detection error: $_" "WARN"};try{$int=Get-WmiObject Win32_VideoController|Where-Object{$_.Name -like "*Intel*"};$int|ForEach-Object{$gpu+=@{Type="Intel";Name=$_.Name;DeviceID=$_.PNPDeviceID;Model=$_.Name};WL "Found Intel GPU: $($_.Name)"}};catch{WL "Intel detection error: $_" "WARN"};return $gpu};function GetDev{WL "Detecting system devices...";$dev=@();$dc=@{"Network Adapters"="Win32_NetworkAdapterConfiguration";"Audio"="Win32_SoundDevice";"Storage Controllers"="Win32_IDEController";"USB Controllers"="Win32_USBController";"Serial/Parallel"="Win32_SerialPort"};$dc.GetEnumerator()|ForEach-Object{try{$wd=Get-WmiObject $_.Value;if($wd){$wd|ForEach-Object{$dev+=@{Type=$_.Key;Name=if($_.Description){$_.Description}elseif($_.Name){$_.Name}else{"Unknown"};Object=$_};WL "Found $($_.Key): $($_.Description -or $_.Name)"}}};catch{WL "$($_.Key) detection error: $_" "WARN"}};try{$mb=Get-WmiObject Win32_BaseBoard;$dev+=@{Type="Motherboard";Name=$mb.Manufacturer+" "+$mb.Product;DeviceID=$mb.SerialNumber};WL "Found Motherboard: $($mb.Manufacturer) $($mb.Product)"}catch{WL "Motherboard detection error: $_" "WARN"};return $dev};function GetSys{WL "Collecting system information...";$os=Get-WmiObject Win32_OperatingSystem;$proc=Get-WmiObject Win32_Processor;return @{OS=$os.Caption;OSBuild=$os.BuildNumber;Architecture=$os.OSArchitecture;Processor=$proc.Name}};function DlNV([hashtable]$g,[hashtable]$s){WL "Preparing NVIDIA driver..." "INFO";try{$url="https://www.nvidia.com/Download/driverResults.aspx/192195";WL "NVIDIA driver URL: $url";WL "Visit: https://www.nvidia.com/Download/index.aspx to download NVIDIA drivers manually" "INFO"}catch{WL "NVIDIA error: $_" "ERROR"}};function DlAMD([hashtable]$g,[hashtable]$s){WL "Preparing AMD driver..." "INFO";try{$url="https://www.amd.com/en/technologies/radeon-software";WL "AMD driver page: $url";WL "Visit: $url to download AMD drivers manually" "INFO"}catch{WL "AMD error: $_" "ERROR"}};function DlINT([hashtable]$g,[hashtable]$s){WL "Preparing Intel driver..." "INFO";try{$url="https://www.intel.com/content/www/us/en/download/785597/intel-arc-graphics-driver.html";WL "Intel Arc page: $url";WL "Visit: $url to download Intel drivers manually" "INFO"}catch{WL "Intel error: $_" "ERROR"}};function DlChip([hashtable]$s){WL "Detecting chipset drivers..." "INFO";$mb=Get-WmiObject Win32_BaseBoard;$mfg=$mb.Manufacturer.ToLower();$urls=@{};if($mfg -like "*intel*"){$urls["Intel Chipset"]="https://www.intel.com/content/www/us/en/download/17596/intel-chipset-device-software.html"}elseif($mfg -like "*amd*"){$urls["AMD Chipset"]="https://www.amd.com/en/support"};$urls.GetEnumerator()|ForEach-Object{WL "Chipset driver: $($_.Key) - $($_.Value)" "INFO"};return $urls};function Main{Write-Host "========================================" -ForegroundColor Cyan;Write-Host "  Universal Driver Installer Script" -ForegroundColor Cyan;Write-Host "========================================" -ForegroundColor Cyan;WL "Script started";if(-not([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]"Administrator")){WL "ERROR: Administrator privileges required!" "ERROR";Write-Host "Please run PowerShell as Administrator." -ForegroundColor Red;exit 1};if(-not(Test-Path $DP)){New-Item -ItemType Directory -Path $DP|Out-Null};WL "Log file: $LP";Write-Host "";$gpu=GetGPU;$dev=GetDev;$sys=GetSys;Write-Host "`n========== DETECTED HARDWARE ==========" -ForegroundColor Green;Write-Host "GPUs detected: $($gpu.Count)" -ForegroundColor Green;$gpu|ForEach-Object{Write-Host "  - $($_.Type): $($_.Name)" -ForegroundColor Green};Write-Host "`nSystem devices detected: $($dev.Count)" -ForegroundColor Green;$dev|Select-Object -First 5|ForEach-Object{Write-Host "  - $($_.Type): $($_.Name)" -ForegroundColor Green};if($dev.Count -gt 5){Write-Host "  ... and $($dev.Count-5) more devices" -ForegroundColor Green};if($gpu.Count -eq 0 -and $dev.Count -eq 0){WL "No GPU or devices detected" "WARN";Write-Host "`nNo hardware requiring drivers detected." -ForegroundColor Yellow;exit 0};Write-Host "`n========== DRIVER ACQUISITION ==========" -ForegroundColor Green;$gpu|ForEach-Object{switch($_.Type){"NVIDIA"{DlNV $_ $sys}"AMD"{DlAMD $_ $sys}"Intel"{DlINT $_ $sys}}};$chip=DlChip $sys;Write-Host "`n========== NEXT STEPS ==========" -ForegroundColor Cyan;Write-Host "1. Download the drivers from the URLs above" -ForegroundColor Cyan;Write-Host "2. Run the installer executables" -ForegroundColor Cyan;Write-Host "3. Restart your computer after installation" -ForegroundColor Cyan;Write-Host "4. Log file saved to: $LP" -ForegroundColor Cyan;WL "Script completed"};Main;Read-Host "Press Enter to exit"
